const { app, BrowserWindow, ipcMain } = require('electron');
const path = require('path');
const isDev = process.env.NODE_ENV === 'development';

function createWindow() {
  const mainWindow = new BrowserWindow({
    width: 1200,
    height: 800,
    webPreferences: {
      preload: path.join(__dirname, 'preload.js'),
      nodeIntegration: false,
      contextIsolation: true,
    },
    titleBarStyle: 'hiddenInset',
  });

  const url = isDev 
    ? 'http://localhost:3000' 
    : `file://${path.join(__dirname, '../out/index.html')}`;

  mainWindow.loadURL(url);

  if (isDev) {
    mainWindow.webContents.openDevTools();
  }
}

app.whenReady().then(() => {
  createWindow();

  app.on('activate', () => {
    if (BrowserWindow.getAllWindows().length === 0) createWindow();
  });
});

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') app.quit();
});

const { contextBridge, ipcRenderer } = require('electron');

contextBridge.exposeInMainWorld('electron', {
  send: (channel, data) => {
    let validChannels = ['toMain'];
    if (validChannels.includes(channel)) {
      ipcRenderer.send(channel, data);
    }
  },
  receive: (channel, func) => {
    let validChannels = ['fromMain'];
    if (validChannels.includes(channel)) {
      ipcRenderer.on(channel, (event, ...args) => func(...args));
    }
  },
});

const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const { createClient } = require('@supabase/supabase-js');
require('dotenv').config({ path: '.env.local' });
require('dotenv').config();

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: "*",
    methods: ["GET", "POST"]
  }
});

// Initialize Supabase with Service Role for admin tasks (cleanup, overrides)
const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

if (!supabaseUrl || !supabaseKey) {
  console.error("CRITICAL: Supabase environment variables missing!");
}

const supabase = createClient(supabaseUrl, supabaseKey);

// State management
const activeUsers = new Map(); // socketId -> UserInfo

io.on('connection', (socket) => {
  console.log('User connected:', socket.id);

  // --- PRESENCE EVENTS ---
  socket.on('presence:join', (user) => {
    activeUsers.set(socket.id, {
      ...user,
      status: 'active',
      last_active: new Date().toISOString()
    });
    broadcastPresence();
  });

  socket.on('presence:update_location', (articleId) => {
    const user = activeUsers.get(socket.id);
    if (user) {
      user.current_article_id = articleId;
      user.last_active = new Date().toISOString();
      broadcastPresence();
    }
  });

  // --- ARTICLE ROOMS ---
  socket.on('article:join', async (articleId) => {
    socket.join(`article:${articleId}`);

    // Fetch existing locks from Supabase
    const { data: locks, error } = await supabase
      .from('field_locks')
      .select('*, profile:profiles(full_name, avatar_color, initials)')
      .eq('article_id', articleId);

    if (!error && locks) {
      socket.emit('article:locks', locks);
    }
  });

  socket.on('article:leave', async (articleId) => {
    socket.leave(`article:${articleId}`);

    // Cleanup any locks held by this socket's user in this article
    const user = activeUsers.get(socket.id);
    if (user) {
      await supabase
        .from('field_locks')
        .delete()
        .eq('article_id', articleId)
        .eq('locked_by', user.id);

      io.to(`article:${articleId}`).emit('field:unlock', { article_id: articleId, all_for_user: user.id });
    }
  });

  // --- FIELD LOCKING EVENTS ---
  socket.on('field:lock', async ({ article_id, field_key }) => {
    const user = activeUsers.get(socket.id);
    if (!user) return;

    const expiresAt = new Date(Date.now() + 5 * 60 * 1000).toISOString(); // 5 min lock

    const { data: lock, error } = await supabase
      .from('field_locks')
      .upsert({
        article_id,
        field_key,
        locked_by: user.id,
        expires_at: expiresAt
      }, { onConflict: 'article_id,field_key' })
      .select('*, profile:profiles(full_name, avatar_color, initials)')
      .single();

    if (!error && lock) {
      io.to(`article:${article_id}`).emit('field:lock', lock);
    } else {
      console.error("Lock error:", error);
    }
  });

  socket.on('field:unlock', async ({ article_id, field_key }) => {
    const user = activeUsers.get(socket.id);
    if (!user) return;

    const { error } = await supabase
      .from('field_locks')
      .delete()
      .match({ article_id, field_key, locked_by: user.id });

    if (!error) {
      io.to(`article:${article_id}`).emit('field:unlock', { article_id, field_key });
    }
  });

  // --- DISCONNECT ---
  socket.on('disconnect', async () => {
    const user = activeUsers.get(socket.id);
    if (user) {
      // Cleanup locks for this user across all articles
      await supabase
        .from('field_locks')
        .delete()
        .eq('locked_by', user.id);

      activeUsers.delete(socket.id);
      broadcastPresence();
    }
    console.log('User disconnected:', socket.id);
  });

  function broadcastPresence() {
    const allUsers = Array.from(activeUsers.values());
    // Deduplicate by user.id — keep the most recent entry per user
    const seen = new Map();
    for (const u of allUsers) {
      if (u.id) seen.set(u.id, u);
    }
    const users = Array.from(seen.values());
    io.emit('presence:update', users);
  }
});

// PERIODIC CLEANUP OF EXPIRED LOCKS (every 30 seconds)
setInterval(async () => {
  const { error } = await supabase
    .from('field_locks')
    .delete()
    .lt('expires_at', new Date().toISOString());

  if (error) console.error("Cleanup error:", error);
}, 30000);

const PORT = process.env.PORT || 3001;
server.listen(PORT, () => {
  console.log(`Socket.IO Collaboration Server running on port ${PORT}`);
});

import { NextRequest, NextResponse } from "next/server";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import { createClient } from "@supabase/supabase-js";

const ADMIN_EMAIL = "toon@vivelevelo.be";

/** Helper: verify the request is coming from the admin */
async function verifyAdmin(req: NextRequest) {
  const authHeader = req.headers.get("Authorization");
  if (!authHeader) return null;

  const token = authHeader.replace("Bearer ", "");
  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  );
  const { data: { user }, error } = await supabase.auth.getUser(token);
  if (error || !user || user.email !== ADMIN_EMAIL) return null;
  return user;
}

/** GET /api/admin/users — list all users with their profiles */
export async function GET(req: NextRequest) {
  const admin = await verifyAdmin(req);
  if (!admin) return NextResponse.json({ error: "Unauthorized" }, { status: 403 });

  try {
    // Fetch auth users + profiles in parallel
    const [{ data: authData, error: authErr }, { data: profiles, error: profileErr }] = await Promise.all([
      supabaseAdmin.auth.admin.listUsers(),
      supabaseAdmin.from("profiles").select("id, full_name, role"),
    ]);

    if (authErr) return NextResponse.json({ error: authErr.message }, { status: 500 });
    if (profileErr) return NextResponse.json({ error: profileErr.message }, { status: 500 });

    const profileMap = new Map((profiles ?? []).map((p: any) => [p.id, p]));

    const users = (authData?.users ?? []).map((u) => {
      const profile = profileMap.get(u.id) as any;
      return {
        id: u.id,
        email: u.email ?? "",
        full_name: profile?.full_name ?? u.user_metadata?.full_name ?? "",
        role: profile?.role ?? "input",
        created_at: u.created_at,
      };
    });

    return NextResponse.json({ users });
  } catch (err: any) {
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}

/** POST /api/admin/users — create a new user */
export async function POST(req: NextRequest) {
  const admin = await verifyAdmin(req);
  if (!admin) return NextResponse.json({ error: "Alleen de beheerder kan gebruikers aanmaken." }, { status: 403 });

  try {
    const { email, full_name, role, password } = await req.json();

    if (!email || !password || !role) {
      return NextResponse.json({ error: "Email, wachtwoord en rol zijn verplicht." }, { status: 400 });
    }

    // Create user
    const { data, error: createError } = await supabaseAdmin.auth.admin.createUser({
      email,
      password,
      email_confirm: true,
      user_metadata: { full_name },
    });

    if (createError) return NextResponse.json({ error: createError.message }, { status: 400 });

    // Update profile (created by DB trigger)
    await supabaseAdmin
      .from("profiles")
      .update({ role, full_name })
      .eq("id", data.user.id);

    return NextResponse.json({ success: true, user: data.user });
  } catch (err: any) {
    return NextResponse.json({ error: err.message ?? "Interne serverfout" }, { status: 500 });
  }
}

/** PATCH /api/admin/users — reset a user's password */
export async function PATCH(req: NextRequest) {
  const admin = await verifyAdmin(req);
  if (!admin) return NextResponse.json({ error: "Unauthorized" }, { status: 403 });

  try {
    const { user_id, password } = await req.json();

    if (!user_id || !password) {
      return NextResponse.json({ error: "user_id en password zijn verplicht." }, { status: 400 });
    }

    if (password.length < 6) {
      return NextResponse.json({ error: "Wachtwoord moet minstens 6 tekens zijn." }, { status: 400 });
    }

    const { error } = await supabaseAdmin.auth.admin.updateUserById(user_id, { password });
    if (error) return NextResponse.json({ error: error.message }, { status: 400 });

    return NextResponse.json({ success: true });
  } catch (err: any) {
    return NextResponse.json({ error: err.message ?? "Interne serverfout" }, { status: 500 });
  }
}

