            <div className="w-5 h-5 rounded-full bg-slate-800 border-2 border-slate-900 flex items-center justify-center text-[8px] font-bold text-slate-500 shadow-sm">
              ?
            </div>
          )}
        </div>
        <span className="text-[9px] font-black uppercase tracking-[0.2em] text-slate-400">
          {activeUsers.length} <span className="text-slate-600 font-medium">{activeUsers.length === 1 ? "gebruiker" : "gebruikers"} online</span>
        </span>
      </div>
      <div className="flex items-center gap-3">
        <div className="flex items-center gap-2 px-2.5 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20">
          <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.5)]" />
          <span className="text-[8px] font-black text-emerald-500 uppercase tracking-widest">Cloud Sync Actief</span>
        </div>
      </div>
    </div>
  );
}
import WizardStepper from "@/components/wizard/WizardStepper";
import dynamic from "next/dynamic";

// PDF components often need dynamic import with ssr: false in Next.js
const PDFPreview = dynamic(() => import("@/components/preview/PDFPreview"), {
  ssr: false,
});

import { useSocket } from "@/hooks/useSocket";

export default function Home() {
  const { user, setUser, fetchCollections } = useTechPackStore();
  const [initializing, setInitializing] = React.useState(true);

  // Start socket connection when logged in
  useSocket();

  React.useEffect(() => {
    // Initial check
    const initAuth = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      setUser(session?.user ?? null);
      if (session?.user) {
        await fetchCollections();
      }
      setInitializing(false);
    };

    initAuth();

    // Listen for changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      setUser(session?.user ?? null);
      if (session?.user) {
        await fetchCollections();
      } else {
        // Clear local collections if needed or let store handle it
      }
    });

    return () => subscription.unsubscribe();
  }, [setUser, fetchCollections]);

  if (initializing) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-slate-50 gap-4">
        <Loader2 className="w-8 h-8 animate-spin text-slate-900" />
        <p className="text-xs font-bold uppercase tracking-widest text-slate-400">Beveiligde verbinding maken...</p>
      </div>
    );
  }

  if (!user) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-slate-50">
        <LoginForm />
      </div>
    );
  }

  return (
    <Shell
      sidebar={
        <div className="flex flex-col h-full overflow-hidden">
          <PresenceBanner />
          <div className="flex-1 min-h-0">
            <Sidebar />
          </div>
          <div className="border-t border-slate-100 bg-white flex-shrink-0 p-2">
            <WizardStepper />
          </div>
        </div>
      }
      form={<WizardEngine />}
      preview={<PDFPreview />}
    />
  );
}

"use client";

import React from "react";
import { useFieldLock } from "@/hooks/useFieldLock";
import { Lock } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

interface FieldWrapperProps {
  articleId: string;
  fieldKey: string;
  label?: string;
  children: React.ReactElement;
  className?: string;
}

export function FieldWrapper({ articleId, fieldKey, label, children, className }: FieldWrapperProps) {
  const { isLocked, lockedBy, acquireLock, releaseLock } = useFieldLock(articleId, fieldKey);

  const handleFocus = () => {
    acquireLock();
  };

  const handleBlur = () => {
    releaseLock();
  };

  return (
    <div className={`relative ${className || ""}`}>
      {label && (
        <div className="flex justify-between items-center mb-1">
          <label className="text-sm font-medium text-gray-700">{label}</label>
          <AnimatePresence>
            {isLocked && (
              <motion.div
                initial={{ opacity: 0, x: 5 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: 5 }}
                className="flex items-center text-[10px] text-amber-600 bg-amber-50 px-1.5 py-0.5 rounded border border-amber-200"
              >
                <Lock size={10} className="mr-1" />
                <span>{lockedBy} is editing</span>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      )}

      <div 
        onFocusCapture={handleFocus}
        onBlurCapture={handleBlur}
        className="relative"
      >
        {React.cloneElement(children as React.ReactElement<any>, {
          disabled: isLocked || (children.props as any).disabled,
          className: `${(children.props as any).className || ""} ${isLocked ? "bg-gray-50 cursor-not-allowed opacity-75 ring-amber-200" : ""}`
        })}

        {isLocked && (
          <div className="absolute inset-0 z-10 cursor-not-allowed" title={`${lockedBy} is editing`} />
        )}
      </div>
    </div>
  );
}

