        placement_name: "Chest Center", 
        notes: `${pos_under_neck_cm} cm onder de kraag`, 
        width_cm: width_cm, 
        height_cm: height_cm, 
        technique: technique === "screenprint" ? "Screenprint" : "Brodé"
      }
    ];
    updateArticle(collectionId, article.id, { placements: newPlacements });
