"use client";

import React, { useEffect } from "react";
import { socket } from "@/lib/socket";
import { useTechPackStore } from "@/store/useTechPackStore";
import { FieldLock } from "@/types/collaboration";

export function CollaborationProvider({ children }: { children: React.ReactNode }) {
  const { 
    profile, 
    setFieldLock, 
    removeFieldLock, 
    setArticleLocks,
    activeArticleId,
    setActiveUsers
  } = useTechPackStore();

  useEffect(() => {
    if (!profile) return;

    if (!socket.connected) {
      socket.connect();
    }

    // Listen for field locking events
    const onFieldLock = (lock: FieldLock) => {
      setFieldLock(lock);
    };

    const onFieldUnlock = (data: { article_id: string; field_key: string; all_for_user?: string }) => {
      if (data.all_for_user) {
        // Handle bulk unlock if a user leaves
        // (Optional: filter store and remove all for that user)
        // For simplicity, we can just re-fetch locks or handle individually
      } else {
        removeFieldLock(data.article_id, data.field_key);
      }
    };

    const onArticleLocks = (locks: FieldLock[]) => {
      setArticleLocks(locks);
    };

    socket.on("field:lock", onFieldLock);
    socket.on("field:unlock", onFieldUnlock);
    socket.on("article:locks", onArticleLocks);

    return () => {
      socket.off("field:lock", onFieldLock);
      socket.off("field:unlock", onFieldUnlock);
      socket.off("article:locks", onArticleLocks);
    };
  }, [profile, setFieldLock, removeFieldLock, setArticleLocks]);

  // Join article room when active article changes
  useEffect(() => {
    if (activeArticleId && socket.connected) {
      socket.emit("article:join", activeArticleId);

      return () => {
        socket.emit("article:leave", activeArticleId);
      };
    }
  }, [activeArticleId]);

  return <>{children}</>;
}

import { create } from "zustand";
import { persist, createJSONStorage, StateStorage } from "zustand/middleware";
import { get, set, del } from 'idb-keyval';
import { supabase } from "@/lib/supabase";

// Helper to debounce async functions
function debounceAsync<T extends (...args: any[]) => Promise<any>>(
  fn: T,
  ms: number
): (...args: Parameters<T>) => void {
  let timeoutId: NodeJS.Timeout;
  return (...args: Parameters<T>) => {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn(...args), ms);
  };
}

const debouncedSet = debounceAsync(set, 1000);

const idbStorage: StateStorage = {
  getItem: async (name: string): Promise<string | null> => {
    return (await get(name)) || null;
  },
  setItem: async (name: string, value: string): Promise<void> => {
    // Debounce the actual write to disk to prevent UI jank during typing
    debouncedSet(name, value);
  },
  removeItem: async (name: string): Promise<void> => {
    await del(name);
  },
};

/**
 * Storage for base64 image data used in PDFs and local previews.
 * Prevents re-fetching large blobs from Supabase during heavy operations.
 */
export const assetStorage = {
  get: async (id: string): Promise<string | undefined> => {
    return await get(`asset:${id}`);
  },
  set: async (id: string, data: string): Promise<void> => {
    await set(`asset:${id}`, data);
  },
  remove: async (id: string): Promise<void> => {
    await del(`asset:${id}`);
  },
};

import { TechPackArticle, Collection, SizeMeasurement, ArtworkPlacement, PantoneColor, ArticleImage, GarmentType, GenderType, FitType, LabelPosition, PackagingType } from "@/types/tech-pack";
import { PresenceUser, FieldLock } from "@/types/collaboration";

interface TechPackStore {
  collections: Collection[];
  activeCollectionId: string | null;
  activeArticleId: string | null;
  activeStep: number;
  isOnline: boolean;

  // Actions
  setIsOnline: (online: boolean) => void;
  addCollection: (name: string, details?: Partial<Collection>) => Promise<void>;
  addArticle: (collectionId: string, article: Partial<TechPackArticle>) => Promise<void>;
  updateArticle: (collectionId: string, articleId: string, updates: Partial<TechPackArticle>) => Promise<void>;
  removeArticle: (collectionId: string, articleId: string) => Promise<void>;
  removeCollection: (collectionId: string) => Promise<void>;
  setActiveCollection: (id: string | null) => void;
  setActiveArticle: (id: string | null) => void;
  setActiveStep: (step: number) => void;
  duplicateArticle: (collectionId: string, articleId: string) => Promise<void>;
  reorderArticles: (collectionId: string, articles: TechPackArticle[]) => void;
  sortArticlesByName: (collectionId: string) => void;

  // Auth & Cloud Sync
  user: any | null;
  profile: PresenceUser | null;
  setUser: (user: any | null) => void;
  setProfile: (profile: PresenceUser | null) => void;
  fetchCollections: () => Promise<void>;
  uploadArticleImage: (articleId: string, file: File, view: ArticleImage['view']) => Promise<string>;

  // Presence & Locking
  activeUsers: PresenceUser[];
  setActiveUsers: (users: PresenceUser[]) => void;
  lockedFields: Record<string, FieldLock>; // Key: article_id:field_key
  setFieldLock: (lock: FieldLock) => void;
  removeFieldLock: (articleId: string, fieldKey: string) => void;
  setArticleLocks: (locks: FieldLock[]) => void;
}

const DEFAULT_ARTICLE_DATA: Partial<TechPackArticle> = {
  reference_code: "",
  product_name: "Nieuw Artikel",
  garment_type: 'jersey',
  gender: 'unisex',
  fit: 'race',
  brand: 'Vive le Vélo',
  customer_po: "",
  disclaimer_enabled: true,
  disclaimer_text: "Door ondertekening van dit document geeft u akkoord op de bovenstaande specificaties. Kleine afwijkingen in kleur (± 5% Pantone) en maatvoering (± 0.5cm) zijn inherent aan het productieproces en worden aanvaard.",
  status: 'draft',
  version: "1.0",
  packaging: 'polybag',
  label_position: 'neck',
  sizes: [],
  placements: [],
  colors: [],
  images: [],
};

const INITIAL_COLLECTION_ID = "vlv-collection-1";
const INITIAL_ARTICLE_ID = "vlv-article-1";

export const useTechPackStore = create<TechPackStore>()(
  persist(
    (set, get) => ({
      collections: [],
      activeCollectionId: null,
      activeArticleId: null,
      activeStep: 1,
      isOnline: true,
      user: null,
      profile: null,
      activeUsers: [],
      lockedFields: {},

      setProfile: (profile: PresenceUser | null) => set({ profile }),
      setUser: (user: any | null) => set({ user }),

      fetchCollections: async () => {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return;

        // Fetch profile
        const { data: profileData } = await supabase
          .from('profiles')
          .select('*')
          .eq('id', user.id)
          .single();

        if (profileData) {
          set({ 
            user,
            profile: { 
              ...profileData, 
              email: user.email 
            } 
          });
        }

        const { data, error } = await supabase
          .from('collections')
          .select(`
            *,
            articles (
              *,
              sizes (*),
              artwork_placements (*),
              pantone_colors (*),
              article_images (*)
            )
          `)
          .order('created_at', { ascending: false });

        if (error) console.error("Error fetching collections:", error);
        else {
          set({ collections: (data as any) || [] });

          // Re-set active IDs if they were null but we have data
          const state = get();
          if (!state.activeCollectionId && data && data.length > 0) {
            set({ 
              activeCollectionId: data[0].id,
              activeArticleId: data[0].articles?.[0]?.id || null
            });
          }
        }
      },

      addCollection: async (name: string, details?: Partial<Collection>) => {
        const { user } = get();
        if (!user) return;

        const { data, error } = await supabase
          .from('collections')
          .insert([{ 
            name, 
            created_by: user.id,
            season: details?.season || "",
            year: details?.year || new Date().getFullYear(),
            description: details?.description || ""
          }])
          .select()
          .single();

        if (error) console.error("Error adding collection:", error);
        else {
          set((state) => ({
            collections: [
              { ...data, articles: [] },
              ...state.collections
            ],
            activeCollectionId: data.id
          }));
        }
      },

      addArticle: async (collectionId: string, article: Partial<TechPackArticle>) => {
        const { user } = get();
        if (!user) return;

        const { data, error } = await supabase
          .from('articles')
          .insert([{ 
            collection_id: collectionId, 
            product_name: article.product_name || "Nieuw Artikel",
            reference_code: article.reference_code || "",
            status: "draft",
            created_by: user.id
          }])
          .select()
          .single();

        if (error) {
          console.error("Error adding article:", error);
          return;
        }

        set((state) => {
          const newArticle = {
            ...data,
            sizes: [],
            placements: [],
            colors: [],
            images: [],
          } as TechPackArticle;

          return {
            activeArticleId: data.id,
            activeStep: 1,
            collections: state.collections.map((col) =>
              col.id === collectionId 
                ? { ...col, articles: [newArticle, ...col.articles] }
                : col
            ),
          };
        });
      },

      updateArticle: async (collectionId: string, articleId: string, updates: Partial<TechPackArticle>) => {
        // Optimistic UI update
        set((state) => ({
          collections: state.collections.map((col) =>
            col.id === collectionId
              ? {
                  ...col,
                  articles: col.articles.map((art) =>
                    art.id === articleId ? { ...art, ...updates } : art
                  ),
                }
              : col
          ),
        }));

        // Granular Sync to Supabase
        const { sizes, placements, colors, images, ...baseFields } = updates;

        // 1. Update Base Article Fields
        if (Object.keys(baseFields).length > 0) {
          const { error } = await supabase
            .from('articles')
            .update(baseFields)
            .eq('id', articleId);
          if (error) console.error("Error updating article base fields:", error);
        }

        // 2. Handle Relational Updates
        if (sizes) {
          await supabase.from('sizes').delete().eq('article_id', articleId);
          if (sizes.length > 0) {
            await supabase.from('sizes').insert(sizes.map(s => ({ ...s, article_id: articleId })));
          }
        }
        if (colors) {
          await supabase.from('pantone_colors').delete().eq('article_id', articleId);
          if (colors.length > 0) {
            await supabase.from('pantone_colors').insert(colors.map(c => ({ ...c, article_id: articleId })));
          }
        }
        if (placements) {
          await supabase.from('artwork_placements').delete().eq('article_id', articleId);
          if (placements.length > 0) {
            await supabase.from('artwork_placements').insert(placements.map(p => ({ ...p, article_id: articleId })));
          }
        }
      },

      removeArticle: async (collectionId: string, articleId: string) => {
        const { error } = await supabase
          .from('articles')
          .delete()
          .eq('id', articleId);
        if (error) console.error("Error removing article:", error);

        set((state) => {
          const collection = state.collections.find((c) => c.id === collectionId);
          const remainingArticles = collection?.articles.filter((a) => a.id !== articleId) || [];
          const newActiveId =
            state.activeArticleId === articleId
              ? (remainingArticles[0]?.id ?? null)
              : state.activeArticleId;

          return {
            activeArticleId: newActiveId,
            activeStep: 1,
            collections: state.collections.map((col) =>
              col.id === collectionId ? { ...col, articles: remainingArticles } : col
            ),
          };
        });
      },

      removeCollection: async (collectionId: string) => {
        const { error } = await supabase
          .from('collections')
          .delete()
          .eq('id', collectionId);
        if (error) console.error("Error removing collection:", error);

        set((state) => {
          const remainingCollections = state.collections.filter((c) => c.id !== collectionId);
          const newActiveCollectionId =
            state.activeCollectionId === collectionId
              ? (remainingCollections[0]?.id ?? null)
              : state.activeCollectionId;

          const newActiveArticleId = 
            state.activeCollectionId === collectionId
              ? (remainingCollections[0]?.articles?.[0]?.id ?? null)
              : state.activeArticleId;

          return {
            activeCollectionId: newActiveCollectionId,
            activeArticleId: newActiveArticleId,
            activeStep: 1,
            collections: remainingCollections,
          };
        });
      },

      setActiveCollection: (id: string | null) => set({ activeCollectionId: id }),
      setActiveArticle: (id: string | null) => set({ activeArticleId: id, activeStep: 1 }),
      setActiveStep: (step: number) => set({ activeStep: step }),
      setIsOnline: (online: boolean) => set({ isOnline: online }),

      duplicateArticle: async (collectionId: string, articleId: string) => {
        const { user } = get();
        if (!user) return;

        const { data: original, error: fetchError } = await supabase
          .from('articles')
          .select('*, sizes(*), artwork_placements(*), pantone_colors(*), article_images(*)')
          .eq('id', articleId)
          .single();

        if (fetchError || !original) {
          console.error("Error fetching article for duplication:", fetchError);
          return;
        }

        const { data: duplicate, error: insertError } = await supabase
          .from('articles')
          .insert([{
            collection_id: collectionId,
            product_name: `${original.product_name} (Copy)`,
            reference_code: original.reference_code,
            garment_type: original.garment_type,
            gender: original.gender,
            fit: original.fit,
            brand: original.brand,
            customer_po: original.customer_po,
            disclaimer_enabled: original.disclaimer_enabled,
            disclaimer_text: original.disclaimer_text,
            fabric_main: original.fabric_main,
            fabric_secondary: original.fabric_secondary,
            weight_gsm: original.weight_gsm,
            label_type: original.label_type,
            label_position: original.label_position,
            label_content: original.label_content,
            packaging: original.packaging,
            packaging_notes: original.packaging_notes,
            status: "draft",
            created_by: user.id
          }])
          .select()
          .single();

        if (insertError) {
          console.error("Error duplicating article:", insertError);
          return;
        }

        if (original.sizes?.length) {
          await supabase.from('sizes').insert(original.sizes.map(({ id, created_at, ...rest }: any) => ({ ...rest, article_id: duplicate.id })));
        }
        if (original.pantone_colors?.length) {
          await supabase.from('pantone_colors').insert(original.pantone_colors.map(({ id, created_at, ...rest }: any) => ({ ...rest, article_id: duplicate.id })));
        }
        if (original.artwork_placements?.length) {
          await supabase.from('artwork_placements').insert(original.artwork_placements.map(({ id, created_at, ...rest }: any) => ({ ...rest, article_id: duplicate.id })));
        }

        await get().fetchCollections();
        set({ activeArticleId: duplicate.id, activeStep: 1 });
      },

      reorderArticles: (collectionId: string, articles: TechPackArticle[]) =>
        set((state) => ({
          collections: state.collections.map((col) =>
            col.id === collectionId ? { ...col, articles } : col
          ),
        })),

      sortArticlesByName: (collectionId: string) =>
        set((state) => ({
          collections: state.collections.map((col) =>
            col.id === collectionId
              ? {
                  ...col,
                  articles: [...col.articles].sort((a, b) => {
                    const nameA = (a.reference_code || a.product_name || "").toLowerCase();
                    const nameB = (b.reference_code || b.product_name || "").toLowerCase();
                    return nameA.localeCompare(nameB);
                  }),
                }
              : col
          ),
        })),

      uploadArticleImage: async (articleId: string, file: File, view: ArticleImage['view']) => {
        const fileExt = file.name.split('.').pop();
        const fileName = `${articleId}/${view}_${Date.now()}.${fileExt}`;

        const { data, error: uploadError } = await supabase.storage
          .from('tech-pack-assets')
          .upload(fileName, file);

        if (uploadError) throw uploadError;

        const { data: { publicUrl } } = supabase.storage
          .from('tech-pack-assets')
          .getPublicUrl(data.path);

        await supabase
          .from('article_images')
          .insert([{
            article_id: articleId,
            view,
            storage_path: data.path,
            public_url: publicUrl,
            file_name: file.name,
            file_size_kb: Math.round(file.size / 1024)
          }]);

        return publicUrl;
      },

      setActiveUsers: (users: PresenceUser[]) => set({ activeUsers: users }),
      setFieldLock: (lock: FieldLock) => set((state) => ({
        lockedFields: {
          ...state.lockedFields,
          [`${lock.article_id}:${lock.field_key}`]: lock
        }
      })),
      removeFieldLock: (articleId: string, fieldKey: string) => set((state) => {
        const newLocks = { ...state.lockedFields };
        delete newLocks[`${articleId}:${fieldKey}`];
        return { lockedFields: newLocks };
      }),
      setArticleLocks: (locks: FieldLock[]) => set((state) => {
        const newLocks = { ...state.lockedFields };
        locks.forEach(lock => {
          newLocks[`${lock.article_id}:${lock.field_key}`] = lock;
        });
        return { lockedFields: newLocks };
      }),
    }),
    {
      name: "tech-pack-storage",
      storage: createJSONStorage(() => idbStorage),
    }
  )
);
